mapper.select:
SELECT m.message_id, m.sender_id, m.receiver_id, m.group_id,
       m.message_type, m.content, m.status, m.created_at
FROM messages m
WHERE m.group_id = #{groupId}
ORDER BY m.created_at ASC
LIMIT #{limit}

mapper.update:
UPDATE messages
SET status = #{status}
WHERE message_id = #{messageId}
